import pytest
from parse_csv import parse_csv_line


class TestHappyPath:
    """Tests for typical CSV line parsing scenarios."""

    def test_simple_values(self):
        assert parse_csv_line("a,b,c") == ["a", "b", "c"]

    def test_values_with_spaces(self):
        assert parse_csv_line("hello, world, test") == ["hello", " world", " test"]

    def test_mixed_quoted_and_unquoted(self):
        assert parse_csv_line('a,"b,c",d') == ["a", "b,c", "d"]

    def test_empty_values(self):
        assert parse_csv_line("a,,c") == ["a", "", "c"]

    def test_quoted_field_with_spaces(self):
        assert parse_csv_line('"hello, world"') == ["hello, world"]

    def test_quotes_inside_quoted_field(self):
        # Two consecutive double quotes inside quotes represent a single quote
        result = parse_csv_line('"Hello ""World"""')
        # Note: This implementation doesn't handle escaped quotes, just toggles
        # so the result will be ['Hello "World"']
        assert result == ['Hello "World"']


class TestEdgeCases:
    """Tests for boundary and special cases."""

    def test_empty_string(self):
        assert parse_csv_line("") == [""]

    def test_single_value_no_comma(self):
        assert parse_csv_line("hello") == ["hello"]

    def test_empty_fields_at_boundaries(self):
        assert parse_csv_line(",a,b,") == ["", "a", "b", ""]

    def test_multiple_consecutive_commas(self):
        assert parse_csv_line("a,,b") == ["a", "", "b"]

    def test_empty_quoted_field(self):
        assert parse_csv_line('""') == [""]

    def test_multiple_empty_quoted_fields(self):
        assert parse_csv_line('"",""') == ["", ""]

    def test_multiple_quoted_fields(self):
        assert parse_csv_line('"a","b","c"') == ["a", "b", "c"]

    def test_trailing_quote_with_no_comma(self):
        assert parse_csv_line('a"b,c') == ['a"b', 'c']

    def test_only_quotes(self):
        assert parse_csv_line('""""') == ['"']

    def test_just_commas(self):
        assert parse_csv_line(",,,") == ["", "", "", ""]

    def test_whitespace_only_values(self):
        assert parse_csv_line("  ,  ,  ") == ["  ", "  ", "  "]


class TestComplexScenarios:
    """Tests for more complex real-world scenarios."""

    def test_csv_with_newlines_in_values(self):
        # Newlines inside quotes are valid
        assert parse_csv_line('"line1\nline2",data') == ["line1\nline2", "data"]

    def test_real_world_record(self):
        result = parse_csv_line('John,Doe,john.doe@example.com,New York')
        assert result == ["John", "Doe", "john.doe@example.com", "New York"]

    def test_quoted_comma_at_start(self):
        assert parse_csv_line('","a') == [",", "a"]

    def test_quoted_comma_at_end(self):
        assert parse_csv_line('a","') == ["a", ""]

    def test_nearly_quoted_field(self):
        # Quote appears but isn't followed by comma/quote
        assert parse_csv_line('a"b"c,d') == ['a"b"c', 'd']

    def test_mixed_quoting_styles(self):
        result = parse_csv_line('plain,"quoted",also"plain')
        assert result == ['plain', 'quoted', 'also"plain']


class TestErrorCases:
    """Tests for unexpected inputs."""

    def test_none_input(self):
        with pytest.raises(TypeError):
            parse_csv_line(None)

    def test_non_string_input(self):
        with pytest.raises(AttributeError):
            parse_csv_line(12345)

    def test_list_input(self):
        with pytest.raises(AttributeError):
            parse_csv_line(["a", "b", "c"])
